// Extract base64 image data from OpenRouter response
const items = $input.all();
const processedItems = [];

for (const item of items) {
  try {
    const response = item.json;

    // Extract image from response
    let base64Image = '';

    if (response.choices && 
        response.choices[0] && 
        response.choices[0].message && 
        response.choices[0].message.images && 
        response.choices[0].message.images[0] && 
        response.choices[0].message.images[0].image_url && 
        response.choices[0].message.images[0].image_url.url) {

      const imageUrl = response.choices[0].message.images[0].image_url.url;

      // Remove data:image/...;base64, prefix
      base64Image = imageUrl.replace(/^data:image\/[^;]+;base64,/, '');
    } else {
      throw new Error('Image not found in response. Response structure: ' + JSON.stringify(response, null, 2));
    }

    // Get image filename from previous node
    const imagePromptNode = $('Generate Image Prompt').first();
    const imageFilename = imagePromptNode ? imagePromptNode.json.imageFilename : 'image.jpg';

    processedItems.push({
      json: {
        ...item.json,
        base64Image: base64Image,
        imageFilename: imageFilename
      }
    });
  } catch (error) {
    // Pass through error for debugging
    processedItems.push({
      json: {
        ...item.json,
        error: error.message,
        base64Image: ''
      }
    });
  }
}

return processedItems;

// Convert base64 image to binary data for Edit Image node
const items = $input.all();
const processedItems = [];

for (const item of items) {
  try {
    const base64Image = item.json.base64Image;
    const imageFilename = item.json.imageFilename || 'image.jpg';

    if (!base64Image) {
      throw new Error('No base64 image data found');
    }

    // Convert base64 to buffer
    const imageBuffer = Buffer.from(base64Image, 'base64');
    const originalSizeKB = Math.round(imageBuffer.length / 1024);

    // Create binary data for Edit Image node
    // n8n expects binary data in item.binary with a property name
    processedItems.push({
      json: {
        ...item.json,
        originalSizeKB: originalSizeKB,
        imageFilename: imageFilename
      },
      binary: {
        data: {
          data: imageBuffer,
          mimeType: 'image/jpeg',
          fileName: imageFilename
        }
      }
    });
  } catch (error) {
    processedItems.push({
      json: {
        ...item.json,
        error: error.message
      }
    });
  }
}

return processedItems;

// Convert compressed image from Edit Image node back to base64 for GitHub upload
// Note: n8n Edit Image node outputs binary data that needs special handling
const items = $input.all();
const processedItems = [];

for (const item of items) {
  try {
    // Get original data from 'Extract Image Base64' node
    const originalItem = $('Extract Image Base64').first();
    const imageFilename = originalItem ? originalItem.json.imageFilename : item.json.imageFilename;

    // Get compressed image data from Edit Image node
    // n8n stores binary data in item.binary - need to access it correctly
    let compressedBase64 = '';

    // Check for binary data in the item
    if (item.binary) {
      // n8n binary data structure: item.binary[propertyName]
      // The property name is usually 'data' based on how we set it in 'Convert Base64 to Binary'
      const binaryProperty = item.binary.data || item.binary.image || Object.values(item.binary)[0];

      if (binaryProperty) {
        // n8n binary data can be:
        // 1. A Buffer object
        // 2. An object with .data property containing Buffer
        // 3. A filesystem path (string starting with filesystem-)

        let binaryData = null;

        if (Buffer.isBuffer(binaryProperty)) {
          binaryData = binaryProperty;
        } else if (binaryProperty.data) {
          if (Buffer.isBuffer(binaryProperty.data)) {
            binaryData = binaryProperty.data;
          } else if (typeof binaryProperty.data === 'string' && !binaryProperty.data.startsWith('filesystem-')) {
            binaryData = Buffer.from(binaryProperty.data, 'base64');
          }
        } else if (typeof binaryProperty === 'string' && !binaryProperty.startsWith('filesystem-')) {
          // Try to decode as base64
          binaryData = Buffer.from(binaryProperty, 'base64');
        }

        if (binaryData && Buffer.isBuffer(binaryData)) {
          compressedBase64 = binaryData.toString('base64');
          const compressedSizeKB = Math.round(binaryData.length / 1024);
          const originalSizeKB = originalItem ? Math.round(Buffer.from(originalItem.json.base64Image, 'base64').length / 1024) : 0;
          const reduction = originalSizeKB > 0 ? Math.round((1 - compressedSizeKB/originalSizeKB) * 100) : 0;
          console.log(`Image compressed: ${originalSizeKB}KB → ${compressedSizeKB}KB (${reduction}% reduction)`);
        } else {
          console.log('Warning: Binary data is a filesystem reference, using original image');
          throw new Error('Filesystem reference detected');
        }
      } else {
        throw new Error('No binary property found');
      }
    } else {
      throw new Error('No binary data in item');
    }

    // Validate base64 string
    if (!compressedBase64 || compressedBase64.length === 0) {
      throw new Error('Empty base64 string');
    }

    processedItems.push({
      json: {
        ...(originalItem ? originalItem.json : item.json),
        base64Image: compressedBase64,
        imageFilename: imageFilename
      }
    });
  } catch (error) {
    // Fallback to original image if compression fails
    const originalItem = $('Extract Image Base64').first();
    console.log('Error in Convert Compressed to Base64, using original:', error.message);

    if (originalItem && originalItem.json.base64Image) {
      processedItems.push({
        json: {
          ...originalItem.json,
          error: error.message,
          base64Image: originalItem.json.base64Image
        }
      });
    } else {
      // Last resort - pass through with error
      processedItems.push({
        json: {
          ...item.json,
          error: error.message,
          base64Image: ''
        }
      });
    }
  }
}

return processedItems;

// Extract SHA from GitHub response and merge with original data
// Handles both 200 (file exists) and 404 (file doesn't exist) responses
// Also handles case where HTTP Request node fails
const items = $input.all();
const processedItems = [];

// Get original data from previous node
const originalItem = $('Convert Compressed to Base64').first();

// If no items received (HTTP Request failed), use original item directly
if (!items || items.length === 0) {
  if (originalItem && originalItem.json) {
    processedItems.push({
      json: {
        ...originalItem.json,
        imageSha: ''
      }
    });
  }
  return processedItems;
}

for (const item of items) {
  let sha = '';

  try {
    // Check if response has SHA (file exists)
    // GitHub returns sha field when file exists (status 200)
    // When file doesn't exist (404), response has message field instead
    if (item.json && item.json.sha && typeof item.json.sha === 'string') {
      sha = item.json.sha;
    }
    // If response has error message (404) or is empty, sha remains empty string (new file)
  } catch (error) {
    // If there's any error accessing the response, treat as new file (empty sha)
    console.log('Error extracting SHA, treating as new file:', error.message);
    sha = '';
  }

  // Merge original data with SHA
  // Always ensure we have the original data even if SHA extraction failed
  if (originalItem && originalItem.json) {
    processedItems.push({
      json: {
        ...originalItem.json,
        imageSha: sha
      }
    });
  } else if (item && item.json) {
    // Fallback if original item not found
    processedItems.push({
      json: {
        ...item.json,
        imageSha: sha
      }
    });
  }
}

return processedItems;

